   713→          user_id: userId,
   714→          event: {
   715→            type: "gesture",
   716→            gesture: gestureType,
   717→            confidence: 1,
   718→            timestamp: Date.now(),
   719→          },
   720→        });
   721→
   722→        // Reset hold state
   723→        holdGestureRef.current = null;
   724→        holdStartRef.current = null;
   725→        setPendingGestureType(null);
