   804→              });
   805→            }
   806→            return i;
   807→          });
   808→          break;
   809→
   810→        case "r":
   811→        case "R":
   812→          setCanvasOutfitIndex(0);
   813→          break;
   814→
   815→        default: {
   816→          const num = parseInt(e.key);
   817→          if (num >= 1 && num <= 9 && num - 1 < canvasOutfits.length) {
   818→            setCanvasOutfitIndex(num - 1);
