  1200→/* ---------- Waiting Countdown ---------- */
  1201→
  1202→function WaitingCountdown() {
  1203→  const [remaining, setRemaining] = useState(120);
  1204→
  1205→  useEffect(() => {
  1206→    const timer = setInterval(() => {
  1207→      setRemaining((s) => {
  1208→        if (s <= 0) return 0;
  1209→        return s - 1;
  1210→      });
  1211→    }, 1000);
  1212→    return () => clearInterval(timer);
  1213→  }, []);
  1214→
  1215→  const minutes = Math.floor(remaining / 60);
  1216→  const seconds = remaining % 60;
  1217→
  1218→  return (
  1219→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
  1220→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
  1221→    </p>
  1222→  );
  1223→}
